Not sure, that understood your point about `_define_metadata` changes - both `_define_metadata` implementations should deliver the same performance since these implementations differ only by formatting, see example below:
```
num_splits = 4
column_chunksize = 32
column_names = [f"col{x}" for x in range(80)]

# Current `_define_metadata` implementation
def func1(num_splits, column_chunksize, column_names):
    column_widths = []
    for i in range(num_splits):
        if len(column_names) > (column_chunksize * i):
            if len(column_names) > (column_chunksize * (i + 1)):
                column_widths.append(column_chunksize)
            else:
                column_widths.append(len(column_names) - (column_chunksize * i))
        else:
            column_widths.append(0)

    return column_widths

# `fwf_dispatcher` implementation
def func2(num_splits, column_chunksize, column_names):
    column_widths = [
        column_chunksize
        if len(column_names) > (column_chunksize * (i + 1))
        else 0
        if len(column_names) < (column_chunksize * i)
        else len(column_names) - (column_chunksize * i)
        for i in range(num_splits)
    ]

    return column_widths

ans1 = func1(num_splits, column_chunksize, column_names) # [32, 32, 16, 0]
ans2 = func2(num_splits, column_chunksize, column_names) # [32, 32, 16, 0]

assert ans1 == ans2
